/* Minimal vendored progressive-fragment helper for hx-get/hx-target/hx-swap. */
document.addEventListener("click",async e=>{const a=e.target.closest("a[hx-get]");if(!a)return;e.preventDefault();const t=document.querySelector(a.getAttribute("hx-target"));if(!t){location.href=a.href;return}a.setAttribute("aria-busy","true");try{const r=await fetch(a.getAttribute("hx-get"),{headers:{"HX-Request":"true"}});if(!r.ok)throw Error(r.status);const h=await r.text();if(a.getAttribute("hx-swap")==="beforeend")a.remove();t.insertAdjacentHTML("beforeend",h);history.replaceState(null,"",a.href)}catch(_){location.href=a.href}});
